CREATE TABLE `ai_messages` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `session_id` bigint unsigned NOT NULL,
  `role` tinyint NOT NULL COMMENT '1:用户 2:AI助手',
  `input_type` tinyint NOT NULL DEFAULT '1' COMMENT '1:文字 2:语音 3:图片 4:混合',
  `raw_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '原始文字输入',
  `voice_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `image_urls` json DEFAULT NULL,
  `transcribed_text` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '语音转文字结果',
  `ocr_text` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '图片OCR结果',
  `ai_response` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `intent` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '识别的意图类型',
  `entities` json DEFAULT NULL COMMENT '提取的实体（商品名、数量等）',
  `confidence` decimal(5,4) DEFAULT NULL COMMENT '意图置信度',
  `dispatched_module` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '分发到的功能模块',
  `dispatched_action_id` bigint unsigned DEFAULT NULL COMMENT '触发的业务记录ID',
  `processing_time_ms` int DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `ai_messages_session_id_index` (`session_id`),
  KEY `ai_messages_intent_created_at_index` (`intent`,`created_at`),
  CONSTRAINT `ai_messages_session_id_foreign` FOREIGN KEY (`session_id`) REFERENCES `ai_sessions` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=115 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
