--
-- Table structure for table `inventory_daily_snapshots`
--

DROP TABLE IF EXISTS `inventory_daily_snapshots`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `inventory_daily_snapshots` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `store_id` bigint unsigned NOT NULL,
  `product_id` bigint unsigned NOT NULL,
  `date` date NOT NULL,
  `opening_qty` decimal(10,3) NOT NULL DEFAULT '0.000' COMMENT '往日库存（当天第一笔交易前）',
  `received_qty` decimal(10,3) NOT NULL DEFAULT '0.000' COMMENT '今日进货合计',
  `sold_qty` decimal(10,3) NOT NULL DEFAULT '0.000' COMMENT '今日销售出库合计',
  `damage_qty` decimal(10,3) NOT NULL DEFAULT '0.000' COMMENT '今日损耗合计',
  `adjustment_qty` decimal(10,3) NOT NULL DEFAULT '0.000' COMMENT '今日盘点调整',
  `closing_qty` decimal(10,3) NOT NULL DEFAULT '0.000' COMMENT '今日结算库存（实时更新）',
  `sold_out_at` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `inventory_daily_snapshots_store_id_product_id_date_unique` (`store_id`,`product_id`,`date`),
  KEY `inventory_daily_snapshots_store_id_date_index` (`store_id`,`date`),
  KEY `inventory_daily_snapshots_product_id_foreign` (`product_id`),
  CONSTRAINT `inventory_daily_snapshots_product_id_foreign` FOREIGN KEY (`product_id`) REFERENCES `products` (`id`) ON DELETE CASCADE,
  CONSTRAINT `inventory_daily_snapshots_store_id_foreign` FOREIGN KEY (`store_id`) REFERENCES `stores` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=480 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

