DROP TABLE IF EXISTS `weather_logs`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `weather_logs` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `store_id` bigint unsigned NOT NULL,
  `date` date NOT NULL,
  `city` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '香港',
  `weather` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '天气状况，如晴、多云、阵雨',
  `temperature_high` smallint NOT NULL COMMENT '最高气温（摄氏度）',
  `temperature_low` smallint NOT NULL COMMENT '最低气温（摄氏度）',
  `humidity` tinyint NOT NULL COMMENT '湿度百分比',
  `rain_probability` tinyint NOT NULL COMMENT '降雨概率百分比',
  `uv_index` tinyint NOT NULL COMMENT '紫外线指数 1-11',
  `description` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '门店参考天气提示',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `weather_logs_date_city_unique` (`date`,`city`),
  KEY `weather_logs_store_id_index` (`store_id`)
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
