INSERT INTO `weather_logs` VALUES (1,3,'2026-04-16','香港','多云转阵雨',26,22,78,60,6,'午后有阵雨，可能影响客流，建议生鲜门店加强易腐商品保鲜措施并备好雨具供顾客使用。','2026-04-16 16:05:27','2026-04-16 16:05:27'),(2,2,'2026-04-26','香港','多云',28,23,75,20,7,'多云天气，气温适宜，客流正常。注意湿度较高，生鲜商品需加强保鲜措施。','2026-04-26 10:21:08','2026-04-26 10:21:08'),(3,1,'2026-04-27','香港','多云',26,22,82,45,6,'多云潮湿，易有零星阵雨，室外客流可能略降，生鲜注意防潮保鲜，叶菜类需加快周转。','2026-04-27 14:22:59','2026-04-27 14:22:59'),(4,2,'2026-04-28','香港','阵雨',26,22,88,80,4,'预计有阵雨，客流可能略降，请注意生鲜防潮和易腐商品及时补货与储存。','2026-04-28 00:49:09','2026-04-28 00:49:09'),(5,1,'2026-05-11','香港','多云有阵雨',31,26,85,70,11,'未来几日高温潮湿，门店需加强冷链管理，避免生鲜损耗。','2026-05-10 21:39:56','2026-05-10 21:39:56');
/*!40000 ALTER TABLE `weather_logs` ENABLE KEYS */;
UNLOCK TABLES;

